function formatEssayDates(){const t=document.querySelectorAll(".essay-date");t&&t.forEach(function(t){var e=t.getAttribute("data-date"),a=config.language||"en",e=moment(e).locale(a).calendar();t.textContent=e})}try{swup.hooks.on("page:view",formatEssayDates)}catch(t){console.error(t)}document.addEventListener("DOMContentLoaded",formatEssayDates);